(function()
---@class LightClassFactory
---@overload table<string, LightClass>
class = {};

local container = {}; ---@type table<string, LightClass>
local base_cls = {}; ---@class LightClass
local meta_methods = {
    "__mode",
    "__metatable",
    "__tostring",
    "__gc",
    "__add",
    "__sub",
    "__mul",
    "__div",
    "__mod",
    "__pow",
    "__unm",
    "__idiv",
    "__band",
    "__bor",
    "__bxor",
    "__bnot",
    "__shl",
    "__shr",
    "__concat",
    "__len",
    "__eq",
    "__lt",
    "__le",
    "__newindex",
    "__call",
    "__pairs",
    "__close"
};

---@class lc_metatable: metatable
---@field public __name string The meta name of the class
---@field public __cls boolean Indicates that this is a class metatable
---@field public __clsi boolean Indicates that this is an instance metatable

--- Get Lua version as major and minor numbers
---@return number major, number minor
local function get_lua_version()
    local major, minor = _VERSION:match("Lua (%d+)%.(%d+)");
    return tonumber(major), tonumber(minor);
end

--- Lua < 5.4 compatibility
--- Make __tostring method returns class name and address
---@return fun(self: table): string
local function __tostring(self)
    local metatable = getmetatable(self);
    local name = metatable.__name;

    return string.format("%s: %p", name, self);
end

---@generic T: LightClass
---@generic U: LightClass
---@param name `T`
---@param super? U
local function new_class(name, super)
    local cls = {};
    local metatable = {};

    super = type(super) == "table" and super or base_cls;

    local super_metatable = getmetatable(super) or {};

    metatable.__name = name;
    metatable.__tostring = super_metatable.__tostring ~= __tostring
        and super_metatable.__tostring or __tostring;

    metatable.__index = super;
    metatable.__cls = true;
    metatable.__clsi = false;

    for i = 1, #meta_methods do
        local method_name = meta_methods[i];

        if (metatable[method_name] == nil) then
            local super_metamethod = rawget(super_metatable, method_name);
            if (super_metamethod ~= nil) then
                rawset(metatable, method_name, super_metamethod);
            end
        end
    end

    container[name] = cls;

    return setmetatable(cls, metatable);
end

---@generic T: LightClass
---@param cls T
---@param ... any
---@return T
local function new_instance(cls, ...)
    local obj = {};
    local cls_metatable = getmetatable(cls) or {};
    local metatable = {};

    for i = 1, #meta_methods do
        local name = meta_methods[i];
        local method = rawget(cls, name) or rawget(cls_metatable, name);
        if (method ~= nil) then
            rawset(metatable, name, method);
        end
    end

    metatable.__name = cls_metatable.__name;
    metatable.__tostring = cls_metatable.__tostring ~= __tostring
        and cls_metatable.__tostring or __tostring;
    metatable.__call = function()
        error("Cannot call instance directly. Create a new instance from the class.");
    end


    metatable.__index = cls;
    metatable.__cls = false;
    metatable.__clsi = true;

    setmetatable(obj, metatable);

    local __init = rawget(cls, "__init"); ---@type fun(self: T, ...: any): void

    if (type(__init) == "function") then
        __init(obj, ...);
    end

    return obj;
end

--- Create a new class
---@generic T: LightClass
---@param name `T`
---@return T
function class.new(name)
    assert(type(name) == "string", "Class name must be a string.");
    assert(container[name] == nil, "Class '" .. name .. "' is already defined.");
    return new_class(name);
end

--- Create a new class that extends a superclass
---@generic T: LightClass
---@generic U: LightClass
---@param name `T`
---@param super U
---@return T
function class.extend(name, super)
    assert(type(name) == "string", "Class name must be a string.");
    assert(container[name] == nil, "Class '" .. name .. "' is already defined.");
    return new_class(name, super);
end

--- Get the metatable (prototype) of a class or instance
---@generic T: LightClass
---@param obj T
---@return lc_metatable
function class.prototype(obj)
    return getmetatable(obj);
end

--- Check if the object is a class
---@param obj any
---@return boolean
function class.is_class(obj)
    local mt = getmetatable(obj);
    return mt ~= nil and mt.__cls == true;
end

--- Check if the object is an instance of a class
---@param obj any
---@return boolean
function class.is_instance(obj)
    local mt = getmetatable(obj);
    return mt ~= nil and mt.__clsi == true;
end

--- Check if the object is an instance of the specified class or its subclasses
---@generic T: LightClass
---@generic U: LightClass
---@param obj T
---@param cls U
---@return boolean
function class.is_instance_of(obj, cls)
    if (not class.is_instance(obj) or not class.is_class(cls)) then
        return false;
    end

    local obj_mt = class.prototype(obj);
    local cls_mt = class.prototype(cls);

    while (obj_mt ~= nil) do
        if (obj_mt == cls_mt) then
            return true;
        end
        local index = rawget(obj_mt, "__index");
        obj_mt = (type(index) == "table") and class.prototype(index) or nil;
    end

    return false;
end

--- Get the type of the object: "class", "instance", or the standard Lua type
---@param obj any
---@return type | "class" | "instance"
function class.type(obj)
    local mt = getmetatable(obj);
    if (mt == nil) then
        return type(obj);
    end
    if (mt.__cls == true) then
        return "class";
    elseif (mt.__clsi == true) then
        return "instance";
    else
        return type(obj);
    end
end

--- Get the name of the class or instance
---@param obj any
---@return string | nil
function class.name(obj)
    local mt = class.prototype(obj);
    return type(mt) == "table" and mt.__name or nil;
end

setmetatable(class, {
    __index = function(_, name)
        assert(type(name) == "string", "Class name must be a string.");
        assert(container[name] ~= nil, "Class '" .. name .. "' is not defined.");
        return container[name];
    end
});

setmetatable(base_cls, {
    __name = "LightClass",
    __call = function(cls, ...)
        return new_instance(cls, ...);
    end
});

return class;

end)();

local __modules = {}
local __cache = {}
local function __require(name)
  local c = __cache[name]
  if c ~= nil then return c end
  local loader = __modules[name]
  if not loader then error("norm: unknown bundled module '" .. tostring(name) .. "'") end
  local m = loader()
  if m == nil then m = true end
  __cache[name] = m
  return m
end

__modules["utils"] = function()
local require = __require
--- Small helpers used across Norm. No dependencies.
---@class NormUtils
---@field logger fun(level: string, message: string)
local utils = {};

--- Default logger: prints with the Norm tag. Override via the `logger` option.
---@param level string
---@param message string
local function default_log(level, message)
    print(("[norm] [%s] %s"):format(level, message));
end

utils.logger = default_log;

--- Format and emit a log line through the active logger.
---@param level string
---@param fmt string
---@param ... any
---@return nil
function utils.log(level, fmt, ...)
    local ok, msg = pcall(string.format, fmt, ...);
    utils.logger(level, ok and msg or fmt);
end

--- Shallow copy of a table.
---@generic T: table
---@param t T
---@return T
function utils.copy(t)
    local out = {};
    for k, v in pairs(t) do out[k] = v; end
    return out;
end

--- Sorted array of a dictionary's keys (stable SQL output).
---@param dict table<string, any>
---@return string[]
function utils.sorted_keys(dict)
    local keys = {};
    for k in pairs(dict) do keys[#keys + 1] = k; end
    table.sort(keys);
    return keys;
end

--- Naive fallback value escaper (adapters should prefer parameter binding).
---@param value string|number|boolean|nil
---@return string
function utils.escape(value)
    local t = type(value);
    if (value == nil) then return "NULL";
    elseif (t == "boolean") then return value and "1" or "0";
    elseif (t == "number") then return tostring(value); end
    return "'" .. tostring(value):gsub("'", "''") .. "'";
end

--- Assert with the Norm tag. Returns the (truthy) condition on success.
---@generic T
---@param condition T
---@param message string
---@return T
function utils.assert(condition, message)
    if (not condition) then
        error("[norm] " .. message, 2);
    end
    return condition;
end

return utils;
end

__modules["dialect"] = function()
local require = __require
--- SQL dialects: the small syntactic differences between database engines.
--- Adapters expose a dialect so the SQL builder stays engine agnostic.
---@class NormDialects
---@field mysql NormDialect
---@field sqlite NormDialect
local dialect = {};

---@param id string|number
---@return string
local function quote_backtick(id)
    return "`" .. tostring(id):gsub("`", "``") .. "`";
end

---@class NormDialect
---@field name string
---@field quote fun(id: string): string
---@field placeholder fun(index: number): string
---@field autoincrement string
---@field table_suffix string
---@field types table<string, string>

---@type NormDialect
dialect.mysql = {
    name = "mysql",
    quote = quote_backtick,
    placeholder = function() return "?"; end,
    autoincrement = "AUTO_INCREMENT",
    table_suffix = " ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci",
    types = {
        id = "INT", integer = "INT", bigint = "BIGINT", string = "VARCHAR",
        text = "TEXT", float = "FLOAT", double = "DOUBLE", boolean = "TINYINT(1)",
        datetime = "DATETIME", date = "DATE", json = "JSON",
    },
};

---@type NormDialect
dialect.sqlite = {
    name = "sqlite",
    quote = quote_backtick,
    placeholder = function() return "?"; end,
    autoincrement = "AUTOINCREMENT",
    table_suffix = "",
    types = {
        id = "INTEGER", integer = "INTEGER", bigint = "INTEGER", string = "TEXT",
        text = "TEXT", float = "REAL", double = "REAL", boolean = "INTEGER",
        datetime = "TEXT", date = "TEXT", json = "TEXT",
    },
};

---@param name string
---@return NormDialect
function dialect.get(name)
    local d = dialect[name];
    if (not d) then
        error(("[norm] unknown dialect '%s'"):format(tostring(name)));
    end
    return d;
end

return dialect;
end

__modules["types"] = function()
local require = __require
--- Column type factories, exposed as `Norm.types`. Each returns a column
--- descriptor consumed by `orm:define`. Available: `id, integer, bigint, string,
--- text, float, double, boolean, datetime, date, json` plus `raw` for raw SQL
--- defaults. Common options: `{ length, nullable, unique, primary, autoincrement, default }`.
--- ```lua
---     db:define("users", {
---         id         = Norm.types.id(),                              -- INT PK AUTO_INCREMENT
---         name       = Norm.types.string({ length = 64, nullable = false }),
---         email      = Norm.types.string({ length = 128, unique = true }),
---         coins      = Norm.types.integer({ default = 0 }),
---         admin      = Norm.types.boolean({ default = false }),
---         created_at = Norm.types.datetime({ default = Norm.types.raw("CURRENT_TIMESTAMP") }),
---     })
--- ```
---@class NormTypes
local types = {};

---@alias NormColumnKind
---| "id" | "integer" | "bigint" | "string" | "text" | "float"
---| "double" | "boolean" | "datetime" | "date" | "json"

---@class NormColumnOptions
---@field length? number Length for VARCHAR columns.
---@field nullable? boolean Defaults to true (false for primary keys).
---@field unique? boolean
---@field primary? boolean
---@field autoincrement? boolean
---@field default? any Literal value, or `Norm.types.raw(...)` for raw SQL.

---@class NormColumn: NormColumnOptions
---@field kind NormColumnKind
---@field name? string Set by `define()` from the schema key.

---@class NormRawDefault
---@field __raw string

---@param kind NormColumnKind
---@param options? NormColumnOptions
---@return NormColumn
local function make(kind, options)
    options = options or {};
    return {
        kind = kind,
        length = options.length,
        nullable = options.nullable ~= false and not options.primary,
        unique = options.unique == true,
        primary = options.primary == true,
        autoincrement = options.autoincrement == true,
        default = options.default,
    };
end

--- Mark a default value as raw SQL (not quoted), e.g. CURRENT_TIMESTAMP.
---@param sql string
---@return NormRawDefault
function types.raw(sql)
    return { __raw = sql };
end

--- Auto-increment integer primary key.
---@param options? NormColumnOptions
---@return NormColumn
function types.id(options)
    options = options or {};
    options.primary = true;
    options.autoincrement = options.autoincrement ~= false;
    options.nullable = false;
    return make("id", options);
end

--- Integer column (`INT` / SQLite `INTEGER`). Often a foreign-key column.
--- ```lua
---     coins   = Norm.types.integer({ default = 0 }),
---     user_id = Norm.types.integer({ nullable = false }), -- FK column
--- ```
---@param options? NormColumnOptions
---@return NormColumn
function types.integer(options) return make("integer", options); end

--- 64-bit integer (`BIGINT` / SQLite `INTEGER`). For values beyond 32 bits, e.g.
--- Discord/Steam IDs or epoch milliseconds.
--- ```lua
---     steam_id = Norm.types.bigint({ unique = true }),
--- ```
---@param options? NormColumnOptions
---@return NormColumn
function types.bigint(options) return make("bigint", options); end

--- Variable-length string (`VARCHAR(length)` / SQLite `TEXT`). Pass `length` for
--- the VARCHAR size on MySQL (ignored by SQLite, which is typeless).
--- ```lua
---     name  = Norm.types.string({ length = 64, nullable = false }),
---     email = Norm.types.string({ length = 128, unique = true }),
--- ```
---@param options? NormColumnOptions
---@return NormColumn
function types.string(options) return make("string", options); end

--- Unbounded text (`TEXT`). Use for large free-form content where `string`'s
--- length cap is impractical.
--- ```lua
---     bio = Norm.types.text(),
--- ```
---@param options? NormColumnOptions
---@return NormColumn
function types.text(options) return make("text", options); end

--- Single-precision floating point (`FLOAT` / SQLite `REAL`).
--- ```lua
---     ratio = Norm.types.float({ default = 1.0 }),
--- ```
---@param options? NormColumnOptions
---@return NormColumn
function types.float(options) return make("float", options); end

--- Double-precision floating point (`DOUBLE` / SQLite `REAL`). Prefer over
--- `float` when you need more precision (coordinates, money-as-float, etc.).
--- ```lua
---     pos_x = Norm.types.double({ default = 0 }),
--- ```
---@param options? NormColumnOptions
---@return NormColumn
function types.double(options) return make("double", options); end

--- Boolean, stored as `TINYINT(1)` on MySQL / `INTEGER` on SQLite. Norm converts
--- to/from a real Lua boolean automatically (true/false in, true/false out).
--- ```lua
---     admin = Norm.types.boolean({ default = false }),
--- ```
---@param options? NormColumnOptions
---@return NormColumn
function types.boolean(options) return make("boolean", options); end

--- Date + time (`DATETIME` / SQLite `TEXT`). Pair with `Norm.types.raw` to get a
--- DB-side default timestamp.
--- ```lua
---     created_at = Norm.types.datetime({ default = Norm.types.raw("CURRENT_TIMESTAMP") }),
--- ```
---@param options? NormColumnOptions
---@return NormColumn
function types.datetime(options) return make("datetime", options); end

--- Date only (`DATE` / SQLite `TEXT`).
--- ```lua
---     birthday = Norm.types.date(),
--- ```
---@param options? NormColumnOptions
---@return NormColumn
function types.date(options) return make("date", options); end

--- JSON column (`JSON` on MySQL / `TEXT` on SQLite). When a JSON provider is
--- active (auto-detected, or set via the `json` option), Norm (de)serialises it
--- automatically: assign a Lua table and read a Lua table back. With `json =
--- false` it stays a raw string. A `default` must be a valid JSON literal string.
--- ```lua
---     coordinates = Norm.types.json({ default = '{"x":0,"y":0,"z":0}' }),
---     -- char.coordinates = { x = 1, y = 2, z = 3 }; char:save():await()
--- ```
---@param options? NormColumnOptions
---@return NormColumn
function types.json(options) return make("json", options); end

-- ==========================================================================
-- Relations. Declared inside a schema alongside columns; `define` separates
-- them out. They create no SQL column, they describe how to load related rows.
-- ==========================================================================

---@class NormRelation
---@field __relation true
---@field kind "belongs_to"|"has_one"|"has_many"
---@field target string The related table name.
---@field key? string FK column (on this model for belongs_to, on the target otherwise).
---@field otherKey? string Referenced column (defaults to the relevant primary key).
---@field onDelete? string Referential action emitted on the FK (belongs_to only).
---@field onUpdate? string Referential action emitted on the FK (belongs_to only).
---@field name? string Set by define() from the schema key.

--- A referential action for a foreign key: "CASCADE", "SET NULL", "RESTRICT",
--- "NO ACTION" or "SET DEFAULT" (case-insensitive).
---@alias NormReferentialAction
---| "CASCADE" | "SET NULL" | "RESTRICT" | "NO ACTION" | "SET DEFAULT"

---@class NormRelationOptions
---@field key? string FK column name. See each relation for its default.
---@field otherKey? string Referenced column (defaults to the relevant primary key).
---@field onDelete? NormReferentialAction Emitted as `ON DELETE …` on the FK (belongs_to only).
---@field onUpdate? NormReferentialAction Emitted as `ON UPDATE …` on the FK (belongs_to only).

---@param kind string
---@param target string
---@param options? NormRelationOptions
---@return NormRelation
local function relation(kind, target, options)
    options = options or {};
    return {
        __relation = true,
        kind = kind,
        target = target,
        key = options.key,
        otherKey = options.otherKey,
        onDelete = options.onDelete,
        onUpdate = options.onUpdate,
    };
end

--- This record holds a foreign key pointing to one `target` row (the "many" side
--- of a one-to-many, or either side of a one-to-one). `key` defaults to
--- `<relationName>_id`, `otherKey` to the target's primary key.
---
--- This is the ONLY relation that can emit a real SQL `FOREIGN KEY` constraint
--- (its `key` lives on this table). Add `onDelete`/`onUpdate` to control the
--- referential action — emitted by `sync()` when foreign keys are enabled.
--- ```lua
---     db:define("posts", {
---         id      = Norm.types.id(),
---         user_id = Norm.types.integer({ nullable = false }), -- the FK column
---         author  = Norm.types.belongsTo("users", { key = "user_id", onDelete = "CASCADE" }),
---     })
---     -- post:load("author"):await()  /  Post:query():include("author"):all():await()
--- ```
---@param target string
---@param options? NormRelationOptions
---@return NormRelation
function types.belongsTo(target, options) return relation("belongs_to", target, options); end

--- One-to-one inverse: the `target` table holds a foreign key pointing back to a
--- single row of this model. `key` defaults to `<thisTableSingular>_id`,
--- `otherKey` to this primary key. Declare the matching `belongsTo` on the target
--- if you want the FK constraint (the FK column lives there, not here).
--- ```lua
---     db:define("users", {
---         id      = Norm.types.id(),
---         profile = Norm.types.hasOne("profiles", { key = "user_id" }),
---     })
---     -- user:load("profile"):await()  /  User:query():include("profile"):all():await()
--- ```
---@param target string
---@param options? NormRelationOptions
---@return NormRelation
function types.hasOne(target, options) return relation("has_one", target, options); end

--- One-to-many inverse: the `target` table holds a foreign key pointing back to
--- this model's rows. `key` defaults to `<thisTableSingular>_id`, `otherKey` to
--- this primary key. As with `hasOne`, the FK column lives on the target, so put
--- the `belongsTo` (and any `onDelete`) there.
--- ```lua
---     db:define("users", {
---         id    = Norm.types.id(),
---         posts = Norm.types.hasMany("posts", { key = "user_id" }),
---     })
---     -- user:load("posts"):await()  /  User:query():include("posts"):all():await()
--- ```
---@param target string
---@param options? NormRelationOptions
---@return NormRelation
function types.hasMany(target, options) return relation("has_many", target, options); end

return types;
end

__modules["sql"] = function()
local require = __require
--- Pure SQL string builders. They turn model metadata + query state into a
--- parameterised SQL string and a params array. No database access -> testable.
local utils = require("utils");

---@class NormWhere
---@field column string
---@field op string Operator: "=", "!=", "<", ">", "<=", ">=", "LIKE", "IN", "NOT IN".
---@field value any `nil` -> IS [NOT] NULL. For IN/NOT IN an array.
---@field bool? "AND"|"OR" Conjunction with the previous condition.

---@class NormOrder
---@field column string
---@field dir "ASC"|"DESC"

---@class NormQueryState
---@field table string
---@field columns? string[] Selected columns (nil = "*").
---@field wheres NormWhere[]
---@field orders? NormOrder[]
---@field limit? number
---@field offset? number

---@class NormSql
local sql = {};

--- Normalise a Lua value into something a driver can bind.
---@param value any
---@return any
local function normalize(value)
    if (type(value) == "boolean") then return value and 1 or 0; end
    return value;
end
sql.normalize = normalize;

--- Build the column definition fragment for CREATE TABLE.
---@param column NormColumn
---@param d NormDialect
---@return string
local function column_def(column, d)
    -- SQLite needs the exact "INTEGER PRIMARY KEY AUTOINCREMENT" spelling.
    if (column.primary and d.name == "sqlite") then
        local def = d.quote(column.name) .. " INTEGER PRIMARY KEY";
        if (column.autoincrement) then def = def .. " AUTOINCREMENT"; end
        return def;
    end

    local type_sql = d.types[column.kind] or "TEXT";
    if (column.kind == "string" and column.length and d.name ~= "sqlite") then
        type_sql = ("VARCHAR(%d)"):format(column.length);
    end

    local def = d.quote(column.name) .. " " .. type_sql;

    if (column.primary) then
        def = def .. " PRIMARY KEY";
        if (column.autoincrement) then def = def .. " " .. d.autoincrement; end
    else
        if (not column.nullable) then def = def .. " NOT NULL"; end
        if (column.unique) then def = def .. " UNIQUE"; end
    end

    if (column.default ~= nil) then
        if (type(column.default) == "table" and column.default.__raw) then
            def = def .. " DEFAULT " .. column.default.__raw;
        elseif (type(column.default) == "string") then
            def = def .. " DEFAULT '" .. column.default:gsub("'", "''") .. "'";
        elseif (type(column.default) == "boolean") then
            def = def .. " DEFAULT " .. (column.default and "1" or "0");
        else
            def = def .. " DEFAULT " .. tostring(column.default);
        end
    end

    return def;
end

--- A foreign-key constraint to emit inside CREATE TABLE.
---@class NormForeignKey
---@field column string FK column on this table.
---@field ref_table string Referenced table.
---@field ref_column string Referenced column.
---@field on_delete? string Referential action (e.g. "CASCADE").
---@field on_update? string Referential action (e.g. "CASCADE").

--- Build a `FOREIGN KEY (...) REFERENCES ...` table constraint fragment. Works
--- for both MySQL (inline) and SQLite (inline, forward references allowed).
---@param fk NormForeignKey
---@param d NormDialect
---@return string
local function foreign_key_def(fk, d)
    local frag = ("FOREIGN KEY (%s) REFERENCES %s (%s)"):format(
        d.quote(fk.column), d.quote(fk.ref_table), d.quote(fk.ref_column));
    if (fk.on_delete) then frag = frag .. " ON DELETE " .. tostring(fk.on_delete):upper(); end
    if (fk.on_update) then frag = frag .. " ON UPDATE " .. tostring(fk.on_update):upper(); end
    return frag;
end
sql.foreign_key_def = foreign_key_def;

--- CREATE TABLE IF NOT EXISTS. Pass `foreign_keys` to append `FOREIGN KEY`
--- constraints (the caller decides whether to emit them per dialect/options).
---@param table_name string
---@param columns NormColumn[] Ordered list (each has a `.name`).
---@param d NormDialect
---@param foreign_keys? NormForeignKey[] Optional FK constraints to append.
---@return string statement
function sql.create_table(table_name, columns, d, foreign_keys)
    local parts = {};
    for i = 1, #columns do parts[#parts + 1] = column_def(columns[i], d); end
    if (foreign_keys) then
        for i = 1, #foreign_keys do parts[#parts + 1] = foreign_key_def(foreign_keys[i], d); end
    end
    return ("CREATE TABLE IF NOT EXISTS %s (%s)%s"):format(
        d.quote(table_name), table.concat(parts, ", "), d.table_suffix);
end

--- INSERT.
---@param table_name string
---@param data table<string, any>
---@param d NormDialect
---@return string statement, any[] params
function sql.insert(table_name, data, d)
    local cols, marks, params = {}, {}, {};
    for _, key in ipairs(utils.sorted_keys(data)) do
        local value = data[key];
        cols[#cols + 1] = d.quote(key);
        if (value == nil) then
            marks[#marks + 1] = "NULL";
        else
            params[#params + 1] = normalize(value);
            marks[#marks + 1] = d.placeholder(#params);
        end
    end
    return ("INSERT INTO %s (%s) VALUES (%s)"):format(
        d.quote(table_name), table.concat(cols, ", "), table.concat(marks, ", ")), params;
end

--- Compile WHERE conditions into a fragment, appending bound params.
--- op "IN"/"NOT IN" expects an array value; nil value -> IS [NOT] NULL.
---@param wheres NormWhere[]
---@param d NormDialect
---@param params any[] Params array to append to (mutated).
---@return string clause
local function compile_where(wheres, d, params)
    if (#wheres == 0) then return ""; end
    local fragments = {};
    for i = 1, #wheres do
        local cond = wheres[i];
        local col = d.quote(cond.column);
        local op = (cond.op or "="):upper();
        local frag;

        if (cond.value == nil) then
            local negated = (op == "!=" or op == "<>" or op == "NOT");
            frag = col .. (negated and " IS NOT NULL" or " IS NULL");
        elseif (op == "IN" or op == "NOT IN") then
            local marks = {};
            for j = 1, #cond.value do
                params[#params + 1] = normalize(cond.value[j]);
                marks[#marks + 1] = d.placeholder(#params);
            end
            frag = ("%s %s (%s)"):format(col, op, table.concat(marks, ", "));
        else
            params[#params + 1] = normalize(cond.value);
            frag = ("%s %s %s"):format(col, op, d.placeholder(#params));
        end

        if (i == 1) then
            fragments[#fragments + 1] = frag;
        else
            fragments[#fragments + 1] = (cond.bool or "AND") .. " " .. frag;
        end
    end
    return " WHERE " .. table.concat(fragments, " ");
end
sql.compile_where = compile_where;

--- SELECT from a query-builder state.
---@param state NormQueryState
---@param d NormDialect
---@return string statement, any[] params
function sql.select(state, d)
    local params = {};
    local columns = "*";
    if (state.columns and #state.columns > 0) then
        local quoted = {};
        for i = 1, #state.columns do quoted[i] = d.quote(state.columns[i]); end
        columns = table.concat(quoted, ", ");
    end

    local statement = ("SELECT %s FROM %s"):format(columns, d.quote(state.table));
    statement = statement .. compile_where(state.wheres, d, params);

    if (state.orders and #state.orders > 0) then
        local parts = {};
        for i = 1, #state.orders do
            local o = state.orders[i];
            parts[#parts + 1] = d.quote(o.column) .. " " .. (o.dir or "ASC");
        end
        statement = statement .. " ORDER BY " .. table.concat(parts, ", ");
    end

    if (state.limit) then
        statement = statement .. " LIMIT " .. tostring(math.floor(state.limit));
        if (state.offset) then
            statement = statement .. " OFFSET " .. tostring(math.floor(state.offset));
        end
    end

    return statement, params;
end

--- SELECT COUNT(*).
---@param state NormQueryState
---@param d NormDialect
---@return string statement, any[] params
function sql.count(state, d)
    local params = {};
    local statement = ("SELECT COUNT(*) AS %s FROM %s"):format(d.quote("count"), d.quote(state.table));
    statement = statement .. compile_where(state.wheres, d, params);
    return statement, params;
end

--- UPDATE from state + data.
---@param state NormQueryState
---@param data table<string, any>
---@param d NormDialect
---@return string statement, any[] params
function sql.update(state, data, d)
    local params = {};
    local sets = {};
    for _, key in ipairs(utils.sorted_keys(data)) do
        local value = data[key];
        if (value == nil) then
            sets[#sets + 1] = d.quote(key) .. " = NULL";
        else
            params[#params + 1] = normalize(value);
            sets[#sets + 1] = d.quote(key) .. " = " .. d.placeholder(#params);
        end
    end
    local statement = ("UPDATE %s SET %s"):format(d.quote(state.table), table.concat(sets, ", "));
    statement = statement .. compile_where(state.wheres, d, params);
    return statement, params;
end

--- DELETE from state.
---@param state NormQueryState
---@param d NormDialect
---@return string statement, any[] params
function sql.delete(state, d)
    local params = {};
    local statement = ("DELETE FROM %s"):format(d.quote(state.table));
    statement = statement .. compile_where(state.wheres, d, params);
    return statement, params;
end

return sql;
end

__modules["promise"] = function()
local require = __require
--- Promise providers: the seam that makes Norm portable across frameworks.
---
--- The ORM core never builds a promise directly; it asks the configured
--- *provider*. A provider is a table exposing three functions:
---   new(executor)  -> promise   -- executor(resolve, reject)
---   resolve(value) -> promise
---   reject(reason) -> promise
---
--- Because the ORM resolves each promise with the already-transformed value,
--- providers need NOT support chaining. That lets us plug in even tiny promise
--- libraries (such as the nanos one).
local class = class; -- light-class global (loaded before this bundle)

--- A promise provider plugs a framework's promise type into Norm.
--- Built-in builders: `Norm.promise.builtin|nanos|cfx`. Validate a custom one
--- with `Norm.promise.define`.
---@class NormPromiseProvider
---@field name string
---@field new fun(executor: fun(resolve: fun(value: any), reject: fun(reason: any))): any Returns a framework promise.
---@field resolve fun(value: any): any Already-resolved promise.
---@field reject fun(reason: any): any Already-rejected promise.
---@field is_promise? fun(value: any): boolean

---@class NormPromiseLib
local promise = {};

-- =====================================================================
-- Built-in zero-dependency promise (used by promise.builtin()).
-- =====================================================================

---@class NormPromise: LightClass
---@field private _state "pending"|"fulfilled"|"rejected"
---@field private _value any
---@field private _queue fun(state: string, value: any)[]
---@field private _await_co thread?
---@overload fun(executor?: fun(resolve: fun(value: any), reject: fun(reason: any))): NormPromise
local NormPromise = class.new("NormPromise");

---@param executor? fun(resolve: fun(value: any), reject: fun(reason: any))
function NormPromise:__init(executor)
    self._state = "pending";
    self._value = nil;
    self._queue = {};
    if (type(executor) == "function") then
        local ok, err = pcall(executor,
            function(v) self:_settle("fulfilled", v); end,
            function(e) self:_settle("rejected", e); end
        );
        if (not ok) then self:_settle("rejected", err); end
    end
end

function NormPromise:_settle(state, value)
    if (self._state ~= "pending") then return; end
    self._state = state;
    self._value = value;
    local queue = self._queue;
    self._queue = {};
    for i = 1, #queue do queue[i](state, value); end
    -- Wake up a coroutine blocked in :await().
    if (self._await_co) then
        local co = self._await_co;
        self._await_co = nil;
        coroutine.resume(co);
    end
end

--- Register handlers; returns a new chained promise.
---@param on_fulfilled? fun(value: any): any
---@param on_rejected? fun(reason: any): any
---@return NormPromise
function NormPromise:next(on_fulfilled, on_rejected)
    return NormPromise(function(resolve, reject)
        local function handle(state, value)
            local handler = (state == "fulfilled") and on_fulfilled or on_rejected;
            if (type(handler) ~= "function") then
                if (state == "fulfilled") then resolve(value); else reject(value); end
                return;
            end
            local ok, result = pcall(handler, value);
            if (not ok) then
                reject(result);
            elseif (type(result) == "table" and type(result.next) == "function") then
                result:next(resolve, reject);
            else
                resolve(result);
            end
        end
        if (self._state == "pending") then
            self._queue[#self._queue + 1] = handle;
        else
            handle(self._state, self._value);
        end
    end);
end

---@param on_rejected fun(reason: any): any
---@return NormPromise
function NormPromise:catch(on_rejected)
    return self:next(nil, on_rejected);
end

--- Block the current coroutine until the promise settles, then return its value
--- (or raise its rejection reason). Must be called from inside a coroutine.
---@return any value
function NormPromise:await()
    if (self._state == "pending") then
        local co, is_main = coroutine.running();
        assert(not is_main, "[norm] NormPromise:await() must be called from a coroutine");
        self._await_co = co;
        coroutine.yield();
    end
    if (self._state == "rejected") then
        error(self._value);
    end
    return self._value;
end

promise.NormPromise = NormPromise;

-- =====================================================================
-- Typed promise overlays (annotations only).
--
-- At runtime every ORM operation returns the configured provider's promise.
-- These subtypes change nothing at runtime; they only narrow `:await()` (and
-- `:next()`) so the editor knows the resolved value's type. Example:
--   NormModel:create(...)         -> NormRecordPromise
--   NormModel:create(...):await() -> NormRecord
-- =====================================================================

---@class NormRecordPromise: NormPromise
---@field await fun(self: NormRecordPromise): NormRecord
---@field next fun(self: NormRecordPromise, on_fulfilled?: fun(value: NormRecord): any, on_rejected?: fun(reason: any): any): NormPromise

---@class NormRecordListPromise: NormPromise
---@field await fun(self: NormRecordListPromise): NormRecord[]
---@field next fun(self: NormRecordListPromise, on_fulfilled?: fun(value: NormRecord[]): any, on_rejected?: fun(reason: any): any): NormPromise

---@class NormRecordOrNilPromise: NormPromise
---@field await fun(self: NormRecordOrNilPromise): NormRecord?
---@field next fun(self: NormRecordOrNilPromise, on_fulfilled?: fun(value: NormRecord?): any, on_rejected?: fun(reason: any): any): NormPromise

---@class NormNumberPromise: NormPromise
---@field await fun(self: NormNumberPromise): number
---@field next fun(self: NormNumberPromise, on_fulfilled?: fun(value: number): any, on_rejected?: fun(reason: any): any): NormPromise

---@class NormBooleanPromise: NormPromise
---@field await fun(self: NormBooleanPromise): boolean
---@field next fun(self: NormBooleanPromise, on_fulfilled?: fun(value: boolean): any, on_rejected?: fun(reason: any): any): NormPromise

---@class NormRowsPromise: NormPromise
---@field await fun(self: NormRowsPromise): table[]
---@field next fun(self: NormRowsPromise, on_fulfilled?: fun(value: table[]): any, on_rejected?: fun(reason: any): any): NormPromise

---@class NormExecResultPromise: NormPromise
---@field await fun(self: NormExecResultPromise): NormExecResult
---@field next fun(self: NormExecResultPromise, on_fulfilled?: fun(value: NormExecResult): any, on_rejected?: fun(reason: any): any): NormPromise

--- Attach an `await` method to a framework-native promise (so `promise:await()`
--- works uniformly across providers). No-op if the promise already exposes one
--- (checked through inheritance, so a lib's own `:await()` is never clobbered).
---@generic T
---@param p T
---@param awaiter fun(self: T): any
---@return T
local function attach_await(p, awaiter)
    if (type(p) == "table" and p.await == nil) then
        rawset(p, "await", awaiter);
    end
    return p;
end

-- =====================================================================
-- Provider validation + built-in providers
-- =====================================================================

--- Validate a custom provider (a table with `new`/`resolve`/`reject`) and return
--- it. Use this to plug any promise system that isn't builtin/nanos/cfx.
--- ```lua
---     local provider = Norm.promise.define({
---         name    = "myfw",
---         new     = function(executor) ... end,
---         resolve = function(value) ... end,
---         reject  = function(reason) ... end,
---     })
--- ```
---@param spec NormPromiseProvider
---@return NormPromiseProvider
function promise.define(spec)
    assert(type(spec) == "table", "[norm] promise provider must be a table");
    assert(type(spec.new) == "function", "[norm] promise provider requires a 'new' function");
    assert(type(spec.resolve) == "function", "[norm] promise provider requires a 'resolve' function");
    assert(type(spec.reject) == "function", "[norm] promise provider requires a 'reject' function");
    return spec;
end

--- Build a provider from any promise CLASS whose constructor is
--- `Class(executor)` (executor receives resolve, reject) — e.g. a custom or
--- framework promise. The class is expected to provide its own await/chaining
--- methods (no `:await()` alias is attached). Use this when your framework's
--- promise differs from nanos-promise / CFX.
--- ```lua
---     local db = Norm.new({ adapter = a, promise = Norm.promise.from_class(Promise) })
--- ```
---@param PromiseClass fun(executor: fun(resolve: fun(value: any), reject: fun(reason: any))): any
---@return NormPromiseProvider
function promise.from_class(PromiseClass)
    assert(PromiseClass ~= nil, "[norm] promise.from_class requires a promise class");
    return {
        name = "class",
        new = function(executor) return PromiseClass(executor); end,
        resolve = function(value) return PromiseClass(function(res) res(value); end); end,
        reject = function(reason) return PromiseClass(function(_, rej) rej(reason); end); end,
    };
end

--- The bundled zero-dependency provider (real then-able with :next/:catch/:await).
--- The default when no provider is configured and the adapter has none.
--- ```lua
---     local db = Norm.new({ adapter = a, promise = Norm.promise.builtin() })
--- ```
---@return NormPromiseProvider
function promise.builtin()
    return {
        name = "builtin",
        new = function(executor) return NormPromise(executor); end,
        resolve = function(value) return NormPromise(function(res) res(value); end); end,
        reject = function(reason) return NormPromise(function(_, rej) rej(reason); end); end,
        is_promise = function(v) return class.is_instance_of(v, NormPromise); end,
    };
end

--- Wrap the nanos-promise `Promise` class so the ORM returns nanos promises.
--- On nanos this is auto-detected, so you rarely pass it explicitly.
--- ```lua
---     local db = Norm.new({ adapter = a, promise = Norm.promise.nanos(Promise) })
--- ```
---@param Promise table The nanos `Promise` class.
---@return NormPromiseProvider
function promise.nanos(Promise)
    assert(Promise, "[norm] promise.nanos requires the nanos Promise class");
    -- nanos promises expose :Await(); add a lowercase :await() alias for uniformity.
    local awaiter = function(self) return self:Await(); end;
    return {
        name = "nanos",
        new = function(executor) return attach_await(Promise(executor), awaiter); end,
        resolve = function(value) return attach_await(Promise(function(res) res(value); end), awaiter); end,
        reject = function(reason) return attach_await(Promise(function(_, rej) rej(reason); end), awaiter); end,
        is_promise = function(v)
            local mt = type(v) == "table" and getmetatable(v);
            return mt ~= nil and mt.__name == "Promise";
        end,
    };
end

--- Wrap FiveM's native `promise` library. The oxmysql adapter uses this by
--- default, so you rarely pass it explicitly.
--- ```lua
---     local db = Norm.new({ adapter = a, promise = Norm.promise.cfx() })
--- ```
---@param lib? table The CFX `promise` library (defaults to the global `promise`).
---@return NormPromiseProvider
function promise.cfx(lib)
    lib = lib or _ENV.promise;
    assert(type(lib) == "table" and type(lib.new) == "function",
        "[norm] promise.cfx requires FiveM's `promise` library");
    -- CFX promises are awaited via Citizen.Await; expose it as :await() too.
    local awaiter = function(self)
        local Citizen = _ENV.Citizen;
        assert(Citizen and Citizen.Await, "[norm] Citizen.Await is unavailable");
        return Citizen.Await(self);
    end;
    return {
        name = "cfx",
        new = function(executor)
            local p = lib.new();
            local ok, err = pcall(executor,
                function(v) p:resolve(v); end,
                function(e) p:reject(e); end);
            if (not ok) then p:reject(err); end
            return attach_await(p, awaiter);
        end,
        resolve = function(value) local p = lib.new(); p:resolve(value); return attach_await(p, awaiter); end,
        reject = function(reason) local p = lib.new(); p:reject(reason); return attach_await(p, awaiter); end,
        is_promise = function(v) return type(v) == "table" and type(v.next) == "function"; end,
    };
end

return promise;
end

