--- Chainable query builder. Terminal methods (all/first/count/update/delete)
--- return a provider promise. The row->record transformation happens inside the
--- single promise, so providers never need chaining support.
---
--- NOTE: terminals are annotated with a typed promise (e.g. NormRecordListPromise)
--- so `:await()` knows the resolved type. At runtime you get the configured
--- provider's promise; await it with `:await()` or chain per your provider.
local class = class;
local sqlmod = require("sql");

---@class NormQueryBuilder: LightClass
---@field model NormModel
---@field private _state NormQueryState
---@overload fun(model: NormModel): NormQueryBuilder
local NormQueryBuilder = class.new("NormQueryBuilder");

---@param model NormModel
function NormQueryBuilder:__init(model)
    self.model = model;
    self._state = {
        table = model.table,
        columns = nil,
        wheres = {},
        orders = {},
        limit = nil,
        offset = nil,
        includes = nil,
    };
end

--- Eager-load the given relations with the result (one batched query per
--- relation — no N+1), attaching them to each returned record.
--- ```lua
---     local users = User:query():include("posts", "profile"):all():await()
---     print(#users[1].posts)
--- ```
---@param ... string relation names declared in the model's schema
---@return NormQueryBuilder self
function NormQueryBuilder:include(...)
    self._state.includes = self._state.includes or {};
    local names = { ... };
    for i = 1, #names do
        self._state.includes[#self._state.includes + 1] = names[i];
    end
    return self;
end

--- Restrict selected columns. select("id","name") or select({"id","name"}).
---@param ... string|string[]
---@return NormQueryBuilder self
function NormQueryBuilder:select(...)
    local args = { ... };
    if (#args == 1 and type(args[1]) == "table") then args = args[1]; end
    self._state.columns = args;
    return self;
end

---@param self NormQueryBuilder
---@param column string|table<string, any>
---@param op? string
---@param value? any
---@param bool "AND"|"OR"
---@return NormQueryBuilder self
local function push_where(self, column, op, value, bool)
    if (type(column) == "table") then
        for k, v in pairs(column) do
            self._state.wheres[#self._state.wheres + 1] =
                { column = k, op = "=", value = v, bool = bool };
        end
        return self;
    end
    if (value == nil) then value = op; op = "="; end
    self._state.wheres[#self._state.wheres + 1] =
        { column = column, op = op, value = value, bool = bool };
    return self;
end

--- Add an AND condition. Forms: `where(col, value)`, `where(col, op, value)` or
--- `where({ col = value, ... })`. Chainable with the other `where_*` helpers.
--- ```lua
---     User:query():where("coins", ">", 100):where("admin", true):all():await()
--- ```
---@param column string|table<string, any>
---@param op? string Operator, or the value when called with 2 args.
---@param value? any
---@return NormQueryBuilder self
function NormQueryBuilder:where(column, op, value)
    return push_where(self, column, op, value, "AND");
end

--- OR variant of `where`.
---@param column string|table<string, any>
---@param op? string
---@param value? any
---@return NormQueryBuilder self
function NormQueryBuilder:or_where(column, op, value)
    return push_where(self, column, op, value, "OR");
end

--- Add a `column IN (...)` condition.
--- ```lua
---     User:query():where_in("id", { 1, 2, 3 }):all():await()
--- ```
---@param column string
---@param list any[]
---@return NormQueryBuilder self
function NormQueryBuilder:where_in(column, list)
    self._state.wheres[#self._state.wheres + 1] =
        { column = column, op = "IN", value = list, bool = "AND" };
    return self;
end

---@param column string
---@return NormQueryBuilder self
function NormQueryBuilder:where_null(column)
    self._state.wheres[#self._state.wheres + 1] =
        { column = column, op = "=", value = nil, bool = "AND" };
    return self;
end

---@param column string
---@return NormQueryBuilder self
function NormQueryBuilder:where_not_null(column)
    self._state.wheres[#self._state.wheres + 1] =
        { column = column, op = "!=", value = nil, bool = "AND" };
    return self;
end

--- Add an ORDER BY clause (call again for secondary orderings).
--- ```lua
---     User:query():order("coins", "DESC"):order("name"):all():await()
--- ```
---@param column string
---@param dir? "ASC"|"DESC"
---@return NormQueryBuilder self
function NormQueryBuilder:order(column, dir)
    self._state.orders[#self._state.orders + 1] =
        { column = column, dir = (dir or "ASC"):upper() };
    return self;
end

--- Limit the number of rows (pair with `:offset()` for pagination).
--- ```lua
---     local page = User:query():order("id"):limit(10):offset(20):all():await()
--- ```
---@param n number
---@return NormQueryBuilder self
function NormQueryBuilder:limit(n) self._state.limit = n; return self; end

--- Skip `n` rows (use with `:limit()`).
---@param n number
---@return NormQueryBuilder self
function NormQueryBuilder:offset(n) self._state.offset = n; return self; end

-- ---------- terminal methods (return promises) ----------

--- Execute the query and resolve with all matching records.
--- ```lua
---     local users = User:query():where("admin", true):all():await()
--- ```
---@return NormRecordListPromise promise resolving to NormRecord[]
function NormQueryBuilder:all()
    local model = self.model;
    local includes = self._state.includes;
    if (includes and #includes > 0) then
        return model.orm:_query_with_includes(model, self._state, includes, false);
    end
    local d = model.orm.adapter:get_dialect();
    local statement, params = sqlmod.select(self._state, d);
    return model.orm:_query_map(statement, params, function(rows)
        local out = {};
        for i = 1, #rows do out[i] = model:wrap(rows[i]); end
        return out;
    end);
end

--- Execute the query with LIMIT 1 and resolve with the first record (or nil).
--- ```lua
---     local newest = User:query():order("id", "DESC"):first():await()
--- ```
---@return NormRecordOrNilPromise promise resolving to NormRecord|nil
function NormQueryBuilder:first()
    self._state.limit = 1;
    local model = self.model;
    local includes = self._state.includes;
    if (includes and #includes > 0) then
        return model.orm:_query_with_includes(model, self._state, includes, true);
    end
    local d = model.orm.adapter:get_dialect();
    local statement, params = sqlmod.select(self._state, d);
    return model.orm:_query_map(statement, params, function(rows)
        local row = rows[1];
        return row and model:wrap(row) or nil;
    end);
end

--- Resolve with the COUNT(*) for the current conditions.
--- ```lua
---     local admins = User:query():where("admin", true):count():await()
--- ```
---@return NormNumberPromise promise resolving to number
function NormQueryBuilder:count()
    local model = self.model;
    local d = model.orm.adapter:get_dialect();
    local statement, params = sqlmod.count(self._state, d);
    return model.orm:_query_map(statement, params, function(rows)
        local row = rows[1] or {};
        return tonumber(row.count or row.COUNT or row["COUNT(*)"]) or 0;
    end);
end

--- Bulk-update every matching row in one statement (no records loaded).
--- Resolves with the affected row count.
--- ```lua
---     local n = User:query():where("admin", true):update({ coins = 0 }):await()
--- ```
---@param data table<string, any>
---@return NormNumberPromise promise resolving to number
function NormQueryBuilder:update(data)
    local model = self.model;
    local d = model.orm.adapter:get_dialect();
    local statement, params = sqlmod.update(self._state, model:_encode_write(data), d);
    return model.orm:_execute_map(statement, params, function(res)
        return res and res.affectedRows or 0;
    end);
end

--- Bulk-delete every matching row in one statement. Resolves with the affected
--- row count.
--- ```lua
---     local n = User:query():where("coins", 0):delete():await()
--- ```
---@return NormNumberPromise promise resolving to number
function NormQueryBuilder:delete()
    local model = self.model;
    local d = model.orm.adapter:get_dialect();
    local statement, params = sqlmod.delete(self._state, d);
    return model.orm:_execute_map(statement, params, function(res)
        return res and res.affectedRows or 0;
    end);
end

return NormQueryBuilder;
end

__modules["model"] = function()
local require = __require
--- Model (table manager, class-level ops) and Record (one row, instance ops).
--- `Orm:define` builds a Model + a dedicated Record subclass per table.
local class = class;
local utils = require("utils");
local sqlmod = require("sql");
local NormQueryBuilder = require("query");

---@class NormModelModule
---@field Record NormRecord
---@field Model NormModel
---@field define fun(orm: NormOrm, table_name: string, schema: table<string, NormColumn>): NormModel
local module = {};

-- ==========================================================================
-- Record: one database row.
-- ==========================================================================

--- A single row. Column values are plain fields (e.g. `record.name`).
---@class NormRecord: LightClass
---@field package __model NormModel
---@field package __persisted boolean
---@field [string] any Column values.
local NormRecord = class.new("NormRecord");

---@param model NormModel
---@param row? table<string, any>
---@param persisted? boolean
function NormRecord:__init(model, row, persisted)
    self.__model = model;
    self.__persisted = persisted == true;
    if (type(row) == "table") then
        -- `parse` decodes DB representations (boolean 1/0, json strings). It only
        -- applies to rows loaded from the database; a user-built record already
        -- holds Lua values, so they are stored verbatim.
        for i = 1, #model.columns do
            local col = model.columns[i];
            local value = row[col.name];
            if (value ~= nil) then
                self[col.name] = self.__persisted and model:parse(col, value) or value;
            end
        end
    end
end

--- Plain `{ column = value }` table for this record (e.g. to serialise it).
--- ```lua
---     local data = user:to_table() --> { id = 1, name = "John", ... }
--- ```
---@return table<string, any>
function NormRecord:to_table()
    local out = {};
    local cols = self.__model.columns;
    for i = 1, #cols do
        local name = cols[i].name;
        if (self[name] ~= nil) then out[name] = self[name]; end
    end
    return out;
end

---@private
---@return table<string, any>
function NormRecord:_persistable()
    local out = {};
    local cols = self.__model.columns;
    for i = 1, #cols do
        local name = cols[i].name;
        if (self[name] ~= nil) then out[name] = self[name]; end
    end
    return out;
end

--- Persist the record: INSERT if new, UPDATE if it was loaded from the database.
--- Resolves with the record itself.
--- ```lua
---     local user = User:find(1):await()
---     user.coins = user.coins + 50
---     user:save():await()
--- ```
---@return NormRecordPromise promise resolving to NormRecord (self)
function NormRecord:save()
    local model = self.__model;
    local orm = model.orm;
    local d = orm.adapter:get_dialect();
    local data = self:_persistable();

    if (self.__persisted) then
        utils.assert(model.primary_key, ("model '%s' has no primary key; cannot update"):format(model.table));
        local pk = model.primary_key;
        data[pk] = nil;
        local state = { table = model.table, wheres = { { column = pk, op = "=", value = self[pk] } } };
        local statement, params = sqlmod.update(state, model:_encode_write(data), d);
        return orm:_execute_map(statement, params, function() return self; end);
    end

    if (model.autoincrement_pk) then data[model.primary_key] = nil; end
    local statement, params = sqlmod.insert(model.table, model:_encode_write(data), d);
    return orm:_execute_map(statement, params, function(res)
        self.__persisted = true;
        if (model.autoincrement_pk and res and res.insertId ~= nil) then
            self[model.primary_key] = res.insertId;
        end
        return self;
    end);
end

--- DELETE this record from the database by its primary key. Resolves with the
--- record (now flagged as not persisted, so a later `:save()` re-inserts it).
--- ```lua
---     local user = User:find(1):await()
---     user:delete():await()
--- ```
---@return NormRecordPromise promise resolving to NormRecord (self)
function NormRecord:delete()
    local model = self.__model;
    utils.assert(model.primary_key, ("model '%s' has no primary key; cannot delete"):format(model.table));
    local d = model.orm.adapter:get_dialect();
    local pk = model.primary_key;
    local state = { table = model.table, wheres = { { column = pk, op = "=", value = self[pk] } } };
    local statement, params = sqlmod.delete(state, d);
    return model.orm:_execute_map(statement, params, function()
        self.__persisted = false;
        return self;
    end);
end

--- Re-read this record's columns from the database (discarding local changes).
--- Resolves with the record.
--- ```lua
---     user:reload():await()
--- ```
---@return NormRecordPromise promise resolving to NormRecord (self)
function NormRecord:reload()
    local model = self.__model;
    utils.assert(model.primary_key, ("model '%s' has no primary key; cannot reload"):format(model.table));
    local d = model.orm.adapter:get_dialect();
    local pk = model.primary_key;
    local state = { table = model.table, limit = 1, wheres = { { column = pk, op = "=", value = self[pk] } } };
    local statement, params = sqlmod.select(state, d);
    return model.orm:_query_map(statement, params, function(rows)
        local row = rows[1];
        if (row) then
            for i = 1, #model.columns do
                local col = model.columns[i];
                if (row[col.name] ~= nil) then
                    self[col.name] = model:parse(col, row[col.name]);
                end
            end
        end
        return self;
    end);
end

--- Lazily load a declared relation, cache it on `self[name]`, and resolve with
--- it. Returns a single record (belongs_to / has_one), nil, or an array (has_many).
--- ```lua
---     local author = post:load("author"):await()  -- also sets post.author
---     local posts  = user:load("posts"):await()   -- also sets user.posts (array)
--- ```
---@param name string
---@return NormPromise promise resolving to NormRecord | NormRecord[] | nil
function NormRecord:load(name)
    local model = self.__model;
    local orm = model.orm;
    local rel = model.relations[name];
    utils.assert(rel, ("model '%s' has no relation '%s'"):format(model.table, name));
    local target = orm:model(rel.target);
    utils.assert(target, ("relation '%s': target model '%s' is not defined"):format(name, rel.target));
    local d = orm.adapter:get_dialect();

    if (rel.kind == "belongs_to") then
        local other_key = rel.otherKey or target.primary_key;
        local fk = self[rel.key];
        if (fk == nil) then
            self[name] = nil;
            return orm.provider.resolve(nil);
        end
        local state = { table = target.table, limit = 1, wheres = { { column = other_key, op = "=", value = fk } } };
        local statement, params = sqlmod.select(state, d);
        return orm:_query_map(statement, params, function(rows)
            local rec = rows[1] and target:wrap(rows[1]) or nil;
            self[name] = rec;
            return rec;
        end);
    end

    -- has_one / has_many
    local local_key = rel.localKey or model.primary_key;
    local local_value = self[local_key];
    if (local_value == nil) then
        self[name] = (rel.kind == "has_many") and {} or nil;
        return orm.provider.resolve(self[name]);
    end
    local state = { table = target.table, wheres = { { column = rel.key, op = "=", value = local_value } } };
    if (rel.kind == "has_one") then state.limit = 1; end
    local statement, params = sqlmod.select(state, d);
    return orm:_query_map(statement, params, function(rows)
        if (rel.kind == "has_one") then
            local rec = rows[1] and target:wrap(rows[1]) or nil;
            self[name] = rec;
            return rec;
        end
        local list = {};
        for i = 1, #rows do list[i] = target:wrap(rows[i]); end
        self[name] = list;
        return list;
    end);
end

module.Record = NormRecord;

-- ==========================================================================
-- Model: one table.
-- ==========================================================================

---@class NormModel: LightClass
---@field orm NormOrm
---@field table string
---@field columns NormColumn[]
---@field columns_by_name table<string, NormColumn>
---@field relations table<string, NormRelation>
---@field primary_key? string
---@field autoincrement_pk boolean
---@field record_class NormRecord
---@overload fun(orm: NormOrm, table_name: string, columns: NormColumn[], record_class: NormRecord): NormModel
local NormModel = class.new("NormModel");

---@param orm NormOrm
---@param table_name string
---@param columns NormColumn[]
---@param record_class NormRecord
function NormModel:__init(orm, table_name, columns, record_class)
    self.orm = orm;
    self.table = table_name;
    self.columns = columns;
    self.columns_by_name = {};
    self.relations = {};
    self.primary_key = nil;
    self.autoincrement_pk = false;
    self.record_class = record_class;
    for i = 1, #columns do
        local c = columns[i];
        self.columns_by_name[c.name] = c;
        if (c.primary) then
            self.primary_key = c.name;
            self.autoincrement_pk = c.autoincrement == true;
        end
    end
end

--- Convert a raw driver value into a Lua value for the given column (decode).
---@param column NormColumn
---@param value any
---@return any
function NormModel:parse(column, value)
    if (value == nil) then return nil; end
    if (column.kind == "boolean") then
        if (type(value) == "number") then return value ~= 0; end
        if (type(value) == "boolean") then return value; end
        return value == "1" or value == "true";
    end
    if (column.kind == "json") then
        -- Some drivers (e.g. mysql2 for JSON columns) already return a table; only
        -- decode raw strings. On failure keep the raw value rather than throwing.
        if (type(value) == "string") then
            local ok, decoded = pcall(self.orm.json.decode, value);
            if (ok) then return decoded; end
        end
        return value;
    end
    return value;
end

--- Convert a Lua value into something storable for the given column (encode).
--- Only `json` tables are transformed; a value already a string is passed
--- through (so a pre-encoded string is never double-encoded).
---@param column NormColumn
---@param value any
---@return any
function NormModel:serialize(column, value)
    if (column.kind == "json" and type(value) == "table") then
        return self.orm.json.encode(value);
    end
    return value;
end

--- Encode a `{ column = value }` write payload (INSERT/UPDATE) column by column.
---@private
---@param data table<string, any>
---@return table<string, any>
function NormModel:_encode_write(data)
    local out = {};
    for k, v in pairs(data) do
        local col = self.columns_by_name[k];
        out[k] = col and self:serialize(col, v) or v;
    end
    return out;
end

--- Wrap a DB row into a persisted record.
---@param row table<string, any>
---@return NormRecord
function NormModel:wrap(row) return self.record_class(self, row, true); end

--- Build an *unsaved* record from a data table (nothing hits the database until
--- you call `:save()`). Useful to prepare a record then persist it later.
--- ```lua
---     local user = User:build({ name = "John" })
---     user.email = "john@x.io"
---     user:save():await()
--- ```
---@param data table<string, any>
---@return NormRecord
function NormModel:build(data) return self.record_class(self, data, false); end

--- Build and immediately INSERT a record. Resolves with the saved record, whose
--- auto-increment primary key is populated.
--- ```lua
---     local user = User:create({ name = "John", email = "john@x.io" }):await()
---     print(user.id) --> 1
--- ```
---@param data table<string, any>
---@return NormRecordPromise promise resolving to NormRecord
function NormModel:create(data) return self:build(data):save(); end

--- Start a chainable query against this model's table.
--- ```lua
---     local admins = User:query():where("admin", true):order("name"):all():await()
--- ```
---@return NormQueryBuilder
function NormModel:query() return NormQueryBuilder(self); end

--- Shortcut for `:query():where(...)`. Accepts `(col, value)`, `(col, op, value)`
--- or a `{ col = value }` table.
--- ```lua
---     local rich = User:where("coins", ">", 100):all():await()
---     local john = User:where({ name = "John" }):first():await()
--- ```
---@param column string|table<string, any>
---@param op? string
---@param value? any
---@return NormQueryBuilder
function NormModel:where(...) return self:query():where(...); end

---@param column string
---@param dir? "ASC"|"DESC"
---@return NormQueryBuilder
function NormModel:order(...) return self:query():order(...); end

---@param n number
---@return NormQueryBuilder
function NormModel:limit(...) return self:query():limit(...); end

---@param ... string|string[]
---@return NormQueryBuilder
function NormModel:select(...) return self:query():select(...); end

--- Resolves with every record in the table.
--- ```lua
---     local users = User:all():await()
---     for _, u in ipairs(users) do print(u.name) end
--- ```
---@return NormRecordListPromise promise resolving to NormRecord[]
function NormModel:all() return self:query():all(); end

--- Resolves with the total row count of the table.
--- ```lua
---     local total = User:count():await()
--- ```
---@return NormNumberPromise promise resolving to number
function NormModel:count() return self:query():count(); end

--- Find a single record by its primary key. Resolves with the record or nil.
--- ```lua
---     local user = User:find(1):await()
---     if (user) then print(user.name) end
--- ```
---@param pk any
---@return NormRecordOrNilPromise promise resolving to NormRecord|nil
function NormModel:find(pk)
    utils.assert(self.primary_key, ("model '%s' has no primary key; cannot find by id"):format(self.table));
    return self:query():where(self.primary_key, pk):first();
end

--- Find the first record matching a `{ column = value }` filter (ANDed).
--- ```lua
---     local user = User:find_by({ email = "john@x.io" }):await()
--- ```
---@param filter table<string, any>
---@return NormRecordOrNilPromise promise resolving to NormRecord|nil
function NormModel:find_by(filter)
    return self:query():where(filter):first();
end

--- Create this model's table (CREATE TABLE IF NOT EXISTS). Prefer `orm:sync()`
--- to create every model at once (it also orders tables by their foreign-key
--- dependencies). Emits this model's `belongsTo` foreign keys when enabled.
--- Resolves with true.
--- ```lua
---     User:sync():await()
--- ```
---@return NormBooleanPromise promise resolving to true
function NormModel:sync()
    local orm = self.orm;
    local d = orm.adapter:get_dialect();
    local fks = orm:_should_emit_fk(d) and orm:_collect_foreign_keys(self) or nil;
    local statement = sqlmod.create_table(self.table, self.columns, d, fks);
    return orm:_execute_map(statement, {}, function() return true; end);
end

module.Model = NormModel;

-- ==========================================================================
-- define()
-- ==========================================================================

local record_counter = 0;
---@param table_name string
---@return string
local function unique_record_name(table_name)
    record_counter = record_counter + 1;
    return ("NormRecord_%s_%d"):format(table_name, record_counter);
end

--- Build a Model (+ dedicated Record subclass) from a schema definition.
---@param orm NormOrm
---@param table_name string
---@param schema table<string, NormColumn>
---@return NormModel
function module.define(orm, table_name, schema)
    utils.assert(type(table_name) == "string", "define: table name must be a string");
    utils.assert(type(schema) == "table", "define: schema must be a table");

    -- Split the schema into columns and relations.
    local columns, relations = {}, {};
    for _, name in ipairs(utils.sorted_keys(schema)) do
        local def = schema[name];
        if (type(def) == "table" and def.__relation) then
            local rel = utils.copy(def);
            rel.name = name;
            relations[name] = rel;
        else
            utils.assert(type(def) == "table" and def.kind,
                ("define: column '%s' is not a valid Norm.types descriptor"):format(name));
            local col = utils.copy(def);
            col.name = name;
            columns[#columns + 1] = col;
        end
    end

    -- Stable order: primary key(s) first, then alphabetical.
    table.sort(columns, function(a, b)
        if (a.primary and not b.primary) then return true; end
        if (b.primary and not a.primary) then return false; end
        return a.name < b.name;
    end);

    -- light-class resolves a constructor with rawget(cls, "__init") (no inheritance
    -- walk), so a Record subclass must define its own __init forwarding to the base.
    -- This also lets users attach custom methods to a model's records.
    local record_class = class.extend(unique_record_name(table_name), NormRecord);
    function record_class:__init(model, row, persisted)
        NormRecord.__init(self, model, row, persisted);
    end

    local model = NormModel(orm, table_name, columns, record_class);

    -- Resolve relation key defaults now that the model (and its primary key) exists.
    local singular = (table_name:gsub("s$", ""));
    for name, rel in pairs(relations) do
        if (rel.kind == "belongs_to") then
            rel.key = rel.key or (name .. "_id");
        else
            rel.key = rel.key or (singular .. "_id");
            rel.localKey = rel.localKey or model.primary_key;
        end
    end
    model.relations = relations;

    return model;
end

return module;
end

__modules["orm"] = function()
local require = __require
--- The Orm root: binds an adapter to a promise provider, owns the model
--- registry, and turns the adapter's callback API into provider promises.
local class = class;
local utils = require("utils");
local sqlmod = require("sql");
local promise = require("promise");
local jsonmod = require("json");
local model_module = require("model");

---@class NormOrm: LightClass
---@field adapter NormAdapter
---@field provider NormPromiseProvider
---@field models table<string, NormModel>
---@field log boolean
---@field foreign_keys boolean|"auto" Whether `sync()` emits SQL FOREIGN KEY constraints.
---@field json NormJsonProvider Provider used to (de)serialise `json` columns.
---@field private _logger fun(level: string, message: string)
---@field private _warned_sqlite_fk boolean
---@overload fun(options: NormOptions): NormOrm
local NormOrm = class.new("NormOrm");

---@class NormOptions
---@field adapter NormAdapter Required. An adapter instance (or duck-typed table).
---@field promise? NormPromiseProvider Promise provider. Defaults to the adapter's, else built-in.
---@field log? boolean Log every executed statement.
---@field logger? fun(level: string, message: string)
---@field foreignKeys? boolean|"auto" Emit SQL FOREIGN KEY constraints from `belongsTo` relations. `"auto"` (default) emits on MySQL, skips on SQLite (with a one-time warning); `true` always emits; `false` never emits (no warning).
---@field json? NormJsonProvider|"auto"|false JSON provider for `json` columns. `"auto"` (default) uses the adapter's, else auto-detects (Nanos `JSON` / Lua `json`), else raw passthrough; `false` disables (de)serialisation.

---@param options NormOptions
function NormOrm:__init(options)
    utils.assert(type(options) == "table", "Norm: options table is required");
    utils.assert(options.adapter and type(options.adapter.raw_query) == "function",
        "Norm: a valid `adapter` is required");

    self.adapter = options.adapter;

    local prov = options.promise;
    if (prov == nil) then
        prov = self.adapter:default_provider() or promise.builtin();
    elseif (type(prov.new) ~= "function"
        or type(prov.resolve) ~= "function"
        or type(prov.reject) ~= "function") then
        -- Not a provider table; assume it's a promise CLASS (callable as Class(executor))
        -- and wrap it. This makes `promise = Promise` (a raw promise class) just work.
        prov = promise.from_class(prov);
    end
    self.provider = promise.define(prov);

    self.models = {};
    self.log = options.log == true;
    self._logger = options.logger or utils.logger;
    self.foreign_keys = (options.foreignKeys == nil) and "auto" or options.foreignKeys;
    self._warned_sqlite_fk = false;

    -- JSON provider for `json` columns: explicit > adapter default > auto-detect.
    -- `false` disables it (raw string passthrough).
    local json_opt = options.json;
    if (json_opt == false) then
        self.json = jsonmod.raw();
    elseif (json_opt ~= nil and json_opt ~= "auto") then
        self.json = jsonmod.define(json_opt);
    else
        local from_adapter;
        if (type(self.adapter.default_json_provider) == "function") then
            from_adapter = self.adapter:default_json_provider();
        end
        self.json = from_adapter or jsonmod.detect();
    end
end

---@private
---@param query string
---@param params? any[]
function NormOrm:_trace(query, params)
    if (not self.log) then return; end
    local suffix = "";
    if (params and #params > 0) then
        local printed = {};
        for i = 1, #params do printed[i] = tostring(params[i]); end
        suffix = " -- [" .. table.concat(printed, ", ") .. "]";
    end
    self._logger("SQL", query .. suffix);
end

--- Run a SELECT and transform the rows inside the promise.
---@param query string
---@param params? any[]
---@param transform fun(rows: table[]): any
---@return NormPromise promise resolving to the transform result
function NormOrm:_query_map(query, params, transform)
    self:_trace(query, params);
    return self.provider.new(function(resolve, reject)
        self.adapter:raw_query(query, params or {}, function(err, rows)
            if (err ~= nil) then return reject(err); end
            local ok, mapped = pcall(transform, rows or {});
            if (not ok) then return reject(mapped); end
            resolve(mapped);
        end);
    end);
end

--- Run a write statement and transform the result inside the promise.
---@param query string
---@param params? any[]
---@param transform fun(result: NormExecResult): any
---@return NormPromise promise resolving to the transform result
function NormOrm:_execute_map(query, params, transform)
    self:_trace(query, params);
    return self.provider.new(function(resolve, reject)
        self.adapter:raw_execute(query, params or {}, function(err, result)
            if (err ~= nil) then return reject(err); end
            local ok, mapped = pcall(transform, result or {});
            if (not ok) then return reject(mapped); end
            resolve(mapped);
        end);
    end);
end

--- Internal: batched eager-load of one relation onto a set of parent records.
--- Runs a single `... IN (...)` query and attaches results. Calls `cb(err?)`.
---@private
---@param model NormModel
---@param mains NormRecord[]
---@param name string
---@param cb fun(err: any)
function NormOrm:_load_include_batch(model, mains, name, cb)
    local rel = model.relations[name];
    if (not rel) then
        return cb(("model '%s' has no relation '%s'"):format(model.table, name));
    end
    local target = self:model(rel.target);
    if (not target) then
        return cb(("relation '%s': target model '%s' is not defined"):format(name, rel.target));
    end
    local d = self.adapter:get_dialect();

    -- Collect the unique, non-nil join keys from the parent records.
    local source_key = (rel.kind == "belongs_to") and rel.key or (rel.localKey or model.primary_key);
    local keys, seen = {}, {};
    for i = 1, #mains do
        local v = mains[i][source_key];
        if (v ~= nil and not seen[v]) then seen[v] = true; keys[#keys + 1] = v; end
    end

    local empty = (rel.kind == "has_many") and {} or nil;
    if (#keys == 0) then
        for i = 1, #mains do mains[i][name] = empty; end
        return cb();
    end

    if (rel.kind == "belongs_to") then
        local other_key = rel.otherKey or target.primary_key;
        local state = { table = target.table, wheres = { { column = other_key, op = "IN", value = keys } } };
        local statement, params = sqlmod.select(state, d);
        self:_trace(statement, params);
        self.adapter:raw_query(statement, params, function(err, rows)
            if (err ~= nil) then return cb(err); end
            local by_key = {};
            for i = 1, #rows do by_key[rows[i][other_key]] = target:wrap(rows[i]); end
            for i = 1, #mains do mains[i][name] = by_key[mains[i][rel.key]]; end
            cb();
        end);
        return;
    end

    -- has_one / has_many: group target rows by their foreign key.
    local state = { table = target.table, wheres = { { column = rel.key, op = "IN", value = keys } } };
    local statement, params = sqlmod.select(state, d);
    self:_trace(statement, params);
    self.adapter:raw_query(statement, params, function(err, rows)
        if (err ~= nil) then return cb(err); end
        local groups = {};
        for i = 1, #rows do
            local k = rows[i][rel.key];
            local g = groups[k];
            if (not g) then g = {}; groups[k] = g; end
            g[#g + 1] = target:wrap(rows[i]);
        end
        for i = 1, #mains do
            local g = groups[mains[i][source_key]] or {};
            mains[i][name] = (rel.kind == "has_one") and (g[1] or nil) or g;
        end
        cb();
    end);
end

--- Internal: run a SELECT then eager-load `includes` (sequentially) before
--- resolving. Returns a single record when `single` is true, else an array.
---@private
---@param model NormModel
---@param state NormQueryState
---@param includes string[]
---@param single boolean
---@return NormPromise
function NormOrm:_query_with_includes(model, state, includes, single)
    local d = self.adapter:get_dialect();
    local statement, params = sqlmod.select(state, d);
    self:_trace(statement, params);
    return self.provider.new(function(resolve, reject)
        self.adapter:raw_query(statement, params or {}, function(err, rows)
            if (err ~= nil) then return reject(err); end
            local records = {};
            for i = 1, #rows do records[i] = model:wrap(rows[i]); end
            if (#records == 0) then
                return resolve(single and nil or records);
            end
            local index = 0;
            local function step()
                index = index + 1;
                local name = includes[index];
                if (not name) then
                    return resolve(single and records[1] or records);
                end
                local ok, err2 = pcall(function()
                    self:_load_include_batch(model, records, name, function(e)
                        if (e ~= nil) then return reject(e); end
                        step();
                    end);
                end);
                if (not ok) then reject(err2); end
            end
            step();
        end);
    end);
end

--- Run a raw parameterised SELECT (bypassing the query builder). Resolves with
--- the raw rows. Bind values with `?` placeholders, never interpolate.
--- ```lua
---     local rows = db:query("SELECT * FROM `users` WHERE `coins` > ?", { 100 }):await()
--- ```
---@param query string
---@param params? any[]
---@return NormRowsPromise promise resolving to table[]
function NormOrm:query(query, params)
    return self:_query_map(query, params, function(rows) return rows; end);
end

--- Run a raw parameterised write (INSERT/UPDATE/DELETE/DDL). Resolves with a
--- `{ affectedRows, insertId }` table.
--- ```lua
---     local res = db:execute("DELETE FROM `users` WHERE `id` = ?", { 1 }):await()
---     print(res.affectedRows)
--- ```
---@param query string
---@param params? any[]
---@return NormExecResultPromise promise resolving to NormExecResult
function NormOrm:execute(query, params)
    return self:_execute_map(query, params, function(result) return result; end);
end

--- Define and register a model from a schema (a `{ column = Norm.types.* }` map).
--- The returned model is your handle for all CRUD/query operations.
--- ```lua
---     local User = db:define("users", {
---         id    = Norm.types.id(),
---         name  = Norm.types.string({ length = 64, nullable = false }),
---         email = Norm.types.string({ length = 128, unique = true }),
---         coins = Norm.types.integer({ default = 0 }),
---     })
--- ```
---@param table_name string
---@param schema table<string, NormColumn>
---@return NormModel
function NormOrm:define(table_name, schema)
    utils.assert(not self.models[table_name],
        ("Norm: model '%s' is already defined"):format(table_name));
    local model = model_module.define(self, table_name, schema);
    self.models[table_name] = model;
    return model;
end

--- Get a previously defined model.
---@param table_name string
---@return NormModel|nil
function NormOrm:model(table_name)
    return self.models[table_name];
end

--- Internal: the FOREIGN KEY constraints to emit for a model, derived from its
--- `belongs_to` relations (the side that physically holds the FK column). The
--- referenced column defaults to the target's primary key, resolved here because
--- the target may have been defined after this model.
---@private
---@param model NormModel
---@return NormForeignKey[]
function NormOrm:_collect_foreign_keys(model)
    local fks = {};
    for _, rel in pairs(model.relations) do
        if (rel.kind == "belongs_to" and rel.key) then
            local target = self.models[rel.target];
            -- Skip relations whose target table isn't registered: we can't emit a
            -- REFERENCES clause to a table Norm doesn't know how to create.
            if (target) then
                fks[#fks + 1] = {
                    column = rel.key,
                    ref_table = rel.target,
                    ref_column = rel.otherKey or target.primary_key or "id",
                    on_delete = rel.onDelete,
                    on_update = rel.onUpdate,
                };
            end
        end
    end
    table.sort(fks, function(a, b) return a.column < b.column; end); -- stable output
    return fks;
end

---@private
---@return boolean
function NormOrm:_has_any_foreign_key()
    for _, m in pairs(self.models) do
        if (#self:_collect_foreign_keys(m) > 0) then return true; end
    end
    return false;
end

--- Internal: decide whether `sync()` should emit FOREIGN KEY constraints for the
--- given dialect, honouring the `foreignKeys` option and warning once on SQLite.
---@private
---@param d NormDialect
---@return boolean
function NormOrm:_should_emit_fk(d)
    local mode = self.foreign_keys;
    if (mode == false) then return false; end

    if (mode == true) then
        if (d.name == "sqlite" and not self._warned_sqlite_fk) then
            self._warned_sqlite_fk = true;
            self._logger("WARN", "[norm] foreignKeys=true on sqlite: constraints are emitted, but enforcement "
                .. "needs `PRAGMA foreign_keys = ON` per connection, which Norm cannot guarantee.");
        end
        return true;
    end

    -- "auto": emit on engines that enforce FKs out of the box (MySQL), skip on
    -- SQLite (per-connection PRAGMA can't be guaranteed). Warn only if relations
    -- actually declare FKs, so FK-less SQLite schemas stay silent.
    if (d.name == "sqlite") then
        if (not self._warned_sqlite_fk and self:_has_any_foreign_key()) then
            self._warned_sqlite_fk = true;
            self._logger("WARN", "[norm] foreign keys are not emitted on sqlite (set foreignKeys=true to force "
                .. "them, or foreignKeys=false to silence this warning).");
        end
        return false;
    end
    return true;
end

--- Internal: order models so a table is created after the tables it references
--- via `belongs_to` (required for inline FKs on MySQL/InnoDB). Returns the table
--- names in creation order plus whether a dependency cycle was detected.
---@private
---@return string[] order, boolean has_cycle
function NormOrm:_sync_order()
    local names = {};
    for name in pairs(self.models) do names[#names + 1] = name; end
    table.sort(names); -- deterministic starting point

    -- deps[name] = sorted list of referenced tables that are also registered models.
    local deps = {};
    for _, name in ipairs(names) do
        local set = {};
        for _, rel in pairs(self.models[name].relations) do
            if (rel.kind == "belongs_to" and rel.target ~= name and self.models[rel.target]) then
                set[rel.target] = true;
            end
        end
        local list = {};
        for t in pairs(set) do list[#list + 1] = t; end
        table.sort(list);
        deps[name] = list;
    end

    local order, visited, on_stack, has_cycle = {}, {}, {}, false;
    local function visit(name)
        if (visited[name]) then return; end
        if (on_stack[name]) then has_cycle = true; return; end
        on_stack[name] = true;
        for _, dep in ipairs(deps[name]) do visit(dep); end
        on_stack[name] = nil;
        visited[name] = true;
        order[#order + 1] = name;
    end
    for _, name in ipairs(names) do visit(name); end
    return order, has_cycle;
end

--- Create the table of every registered model (CREATE TABLE IF NOT EXISTS),
--- in dependency order so foreign keys resolve. When foreign keys are enabled
--- (see the `foreignKeys` option), `belongsTo` relations emit `FOREIGN KEY`
--- constraints. Resolves true.
--- ```lua
---     db:sync():await() -- run once at startup, after defining your models
--- ```
---@return NormBooleanPromise promise resolving to true
function NormOrm:sync()
    local d = self.adapter:get_dialect();
    local emit_fk = self:_should_emit_fk(d);
    local order, has_cycle = self:_sync_order();

    -- Inline FKs need referenced tables first; a cycle can't satisfy that on
    -- engines that check at CREATE time (MySQL). SQLite allows forward refs.
    if (emit_fk and has_cycle and d.name ~= "sqlite") then
        self._logger("WARN", "[norm] cyclic foreign-key dependency detected; CREATE TABLE order cannot satisfy "
            .. "every reference on '" .. d.name .. "'. Consider foreignKeys=false or breaking the cycle.");
    end

    local statements = {};
    for _, name in ipairs(order) do
        local m = self.models[name];
        local fks = emit_fk and self:_collect_foreign_keys(m) or nil;
        statements[#statements + 1] = sqlmod.create_table(m.table, m.columns, d, fks);
    end

    return self.provider.new(function(resolve, reject)
        local index = 0;
        local function step()
            index = index + 1;
            if (index > #statements) then return resolve(true); end
            self:_trace(statements[index], {});
            self.adapter:raw_execute(statements[index], {}, function(err)
                if (err ~= nil) then return reject(err); end
                step();
            end);
        end
        step();
    end);
end

return NormOrm;
end

__modules["adapters.nanos"] = function()
local require = __require
--- Adapter for the Nanos World `Database` object.
--- https://docs.nanos.world/docs/scripting-reference/classes/database
local class = class;
local utils = require("utils");
local NormAdapter = require("adapter");
local promise = require("promise");
local jsonlib = require("json");

---@class NormNanosAdapterOptions: NormAdapterOptions
---@field engine? integer A `DatabaseEngine` enum value (required unless `database` is given).
---@field connection? string Connection string / file path.
---@field pool_size? integer Number of pooled connections (nanos default if omitted).
---@field database? table An already-built nanos `Database` instance to reuse.

---@class NormNanosAdapter: NormAdapter
---@field database table The underlying nanos `Database`.
---@field private _resolved_dialect "mysql"|"sqlite"
---@overload fun(options?: NormNanosAdapterOptions): NormNanosAdapter
local NormNanosAdapter = class.extend("NormNanosAdapter", NormAdapter);

--- Map a Nanos DatabaseEngine to a dialect name.
---@param engine integer
---@return "mysql"|"sqlite"
local function engine_to_dialect(engine)
    local E = _ENV.DatabaseEngine;
    if (E) then
        if (engine == E.SQLite) then return "sqlite"; end
        if (engine == E.PostgreSQL) then return "mysql"; end -- close enough for our SQL
    end
    return "mysql";
end

---@param options? NormNanosAdapterOptions
function NormNanosAdapter:__init(options)
    options = options or {};
    self._resolved_dialect = options.dialect
        or (options.engine ~= nil and engine_to_dialect(options.engine))
        or "sqlite";

    NormAdapter.__init(self, options); -- light-class: explicit super constructor call

    if (options.database) then
        self.database = options.database;
    else
        local Database = _ENV.Database;
        assert(Database, "[norm] Nanos `Database` global is not available");
        assert(options.engine ~= nil, "[norm] nanos adapter requires `engine` or a `database` instance");
        options.engine = options.engine or _ENV.DatabaseEngine.SQLite;
        options.connection = options.connection or "./database.db";
        options.pool_size = options.pool_size or 10;
        -- nanos Database(database_engine, connection_string, pool_size)
        local ok, db = pcall(Database, options.engine, options.connection, options.pool_size);
        if (not ok) then
            utils.log("DB", "nanos connection FAILED ('%s'): %s", tostring(options.connection), tostring(db));
            error(("[norm] failed to open nanos database '%s': %s"):format(tostring(options.connection), tostring(db)));
        end
        self.database = db;
        utils.log("DB", "connected to nanos database '%s' (pool=%d)", tostring(options.connection), options.pool_size);
    end
end

---@return "mysql"|"sqlite"
function NormNanosAdapter:get_dialect_name()
    return self._resolved_dialect or "sqlite";
end

--- If nanos-promise is loaded in this package (global `Promise`), use it.
--- No cross-package import: the nanos package is expected to bundle nanos-promise.
---@return NormPromiseProvider|nil
function NormNanosAdapter:default_provider()
    local P = _ENV.Promise;
    if (type(P) ~= "nil") then
        local ok, provider = pcall(promise.nanos, P);
        if (ok) then return provider; end
    end
    return nil; -- fall back to the built-in provider
end

--- Nanos exposes a global `JSON` class (`stringify`/`parse`); use it to
--- (de)serialise `json` columns automatically.
---@return NormJsonProvider|nil
function NormNanosAdapter:default_json_provider()
    if (type(_ENV.JSON) == "table") then
        local ok, provider = pcall(jsonlib.nanos, _ENV.JSON);
        if (ok) then return provider; end
    end
    return nil; -- fall back to auto-detection / raw passthrough
end

--- Nanos binds parameters with NUMBERED placeholders (`:0`, `:1`, ... 0-indexed),
--- not `?`. Norm's SQL builder emits `?`, so the adapter rewrites them in order.
--- Safe because the builder only ever emits `?` as a placeholder (never inside a
--- string literal; identifiers are backtick-quoted).
---@param query string
---@return string
local function to_nanos_placeholders(query)
    local i = -1;
    return (query:gsub("%?", function() i = i + 1; return ":" .. i; end));
end

--- Internal: run a SELECT (async if available, else synchronous).
---@param db table
---@param query string
---@param params any[]
---@param callback NormQueryCallback
local function do_select(db, query, params, callback)
    params = params or {};
    query = to_nanos_placeholders(query);
    if (type(db.SelectAsync) == "function") then
        -- Nanos signature: SelectAsync(query, callback?, parameters...) -- params are VARARGS.
        db:SelectAsync(query, function(rows) callback(nil, rows or {}); end, table.unpack(params));
    else
        local ok, rows = pcall(function() return db:Select(query, table.unpack(params)); end);
        if (ok) then callback(nil, rows or {}); else callback(rows); end
    end
end

--- Internal: run a write (async if available, else synchronous).
---@param db table
---@param query string
---@param params any[]
---@param callback fun(err: any, affected?: number)
local function do_execute(db, query, params, callback)
    params = params or {};
    query = to_nanos_placeholders(query);
    if (type(db.ExecuteAsync) == "function") then
        -- Nanos signature: ExecuteAsync(query, callback?, parameters...) -- params are VARARGS.
        db:ExecuteAsync(query, function(affected) callback(nil, affected); end, table.unpack(params));
    else
        local ok, affected = pcall(function() return db:Execute(query, table.unpack(params)); end);
        if (ok) then callback(nil, affected); else callback(affected); end
    end
end

---@param query string
---@param params any[]
---@param callback NormQueryCallback
function NormNanosAdapter:raw_query(query, params, callback)
    do_select(self.database, query, params, callback);
end

---@param query string
---@param params any[]
---@param callback NormExecuteCallback
function NormNanosAdapter:raw_execute(query, params, callback)
    local db = self.database;
    local is_insert = query:match("^%s*[Ii][Nn][Ss][Ee][Rr][Tt]") ~= nil;
    local last_id_sql = (self:get_dialect_name() == "sqlite")
        and "SELECT last_insert_rowid() AS id"
        or "SELECT LAST_INSERT_ID() AS id";

    do_execute(db, query, params, function(err, affected)
        if (err ~= nil) then return callback(err); end
        if (not is_insert) then
            return callback(nil, { affectedRows = affected });
        end
        do_select(db, last_id_sql, {}, function(select_err, rows)
            local id = (not select_err) and rows[1] and rows[1].id or nil;
            callback(nil, { affectedRows = affected, insertId = id });
        end);
    end);
end

---@class NormNanosAdapterModule
---@field class NormNanosAdapter
local M = {};

--- Create a Nanos adapter instance (opens/pools a `Database` and logs the
--- connection). Pass it to `Norm.new`.
--- ```lua
---     local adapter = Norm.adapters.nanos.new({
---         engine = DatabaseEngine.SQLite,
---         connection = "./game.db",
---         pool_size = 4, -- optional
---     })
---     local db = Norm.new({ adapter = adapter })
--- ```
---@param options? NormNanosAdapterOptions
---@return NormNanosAdapter
function M.new(options) return NormNanosAdapter(options); end
M.class = NormNanosAdapter;

return M;
end

__modules["adapters.oxmysql"] = function()
local require = __require
--- Adapter for oxmysql (FiveM). https://overextended.dev/oxmysql
local class = class;
local utils = require("utils");
local NormAdapter = require("adapter");
local promise = require("promise");
local jsonlib = require("json");

---@class NormOxMySQLAdapterOptions: NormAdapterOptions
---@field oxmysql? table Inject the oxmysql export (defaults to `exports.oxmysql`).

---@class NormOxMySQLAdapter: NormAdapter
---@field ox table The oxmysql export.
---@overload fun(options?: NormOxMySQLAdapterOptions): NormOxMySQLAdapter
local NormOxMySQLAdapter = class.extend("NormOxMySQLAdapter", NormAdapter);

---@param options? NormOxMySQLAdapterOptions
function NormOxMySQLAdapter:__init(options)
    options = options or {};
    NormAdapter.__init(self, options);
    self.ox = options.oxmysql or (_ENV.exports and _ENV.exports.oxmysql);
    assert(self.ox, "[norm] oxmysql export not found (is the resource a dependency?)");
    self:onReady(function()
        utils.log("DB", "oxmysql connection ready");
    end);
end

--- Wait until oxmysql has started and its connection is up, then run `cb`.
--- Runs in a background thread (Wait yields), so it never blocks construction.
---@param cb? fun(): any
function NormOxMySQLAdapter:onReady(cb)
    local ox = self.ox;
    local CreateThread = _ENV.CreateThread;
    local GetResourceState = _ENV.GetResourceState;
    local Wait = _ENV.Wait;
    local function ready()
        while (GetResourceState and GetResourceState("oxmysql") ~= "started") do
            Wait(50);
        end
        if (ox.awaitConnection) then
            ox:awaitConnection();
        end
        return cb and cb() or true;
    end
    CreateThread(ready);
end

---@return "mysql"
function NormOxMySQLAdapter:get_dialect_name()
    return "mysql";
end

--- FiveM resources have a native `promise` library; use it by default.
---@return NormPromiseProvider|nil
function NormOxMySQLAdapter:default_provider()
    if (type(_ENV.promise) == "table") then
        return promise.cfx(_ENV.promise);
    end
    return nil;
end

--- FiveM exposes a global `json` (`encode`/`decode`); use it to (de)serialise
--- `json` columns automatically.
---@return NormJsonProvider|nil
function NormOxMySQLAdapter:default_json_provider()
    if (type(_ENV.json) == "table") then
        local ok, provider = pcall(jsonlib.lua, _ENV.json);
        if (ok) then return provider; end
    end
    return nil; -- fall back to auto-detection / raw passthrough
end

---@param result number|table
---@return NormExecResult
local function normalize(result)
    if (type(result) == "number") then
        return { affectedRows = result };
    elseif (type(result) == "table") then
        return { affectedRows = result.affectedRows, insertId = result.insertId };
    end
    return {};
end

---@param query string
---@param params any[]
---@param callback NormQueryCallback
function NormOxMySQLAdapter:raw_query(query, params, callback)
    -- oxmysql raises errors server-side rather than passing them to the callback.
    self.ox:query(query, params, function(rows)
        callback(nil, rows or {});
    end);
end

---@param query string
---@param params any[]
---@param callback NormExecuteCallback
function NormOxMySQLAdapter:raw_execute(query, params, callback)
    self.ox:execute(query, params, function(result)
        callback(nil, normalize(result));
    end);
end

---@class NormOxMySQLAdapterModule
---@field class NormOxMySQLAdapter
local M = {};

--- Create an oxmysql adapter instance (waits for oxmysql to be ready and logs
--- the connection). Pass it to `Norm.new`.
--- ```lua
---     local db = Norm.new({ adapter = Norm.adapters.oxmysql.new() })
---     -- defaults to the CFX `promise` provider (use :next / Citizen.Await / :await)
--- ```
---@param options? NormOxMySQLAdapterOptions
---@return NormOxMySQLAdapter
function M.new(options) return NormOxMySQLAdapter(options); end
M.class = NormOxMySQLAdapter;

return M;
end

